<!DOCTYPE html>
<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=yes">
  <title>潮汐抉择 · 织梦版</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }

    body {
      background: transparent;
      padding: 12px;
      font-family: "Helvetica Neue", Helvetica, "PingFang SC", "Hiragino Sans GB", "Noto Sans CJK SC", sans-serif;
      -webkit-font-smoothing: antialiased;
      -moz-osx-font-smoothing: grayscale;
    }

    /* 核心容器 */
    .tide-weaver {
      width: 100%;
      margin: 12px 0;
    }

    /* 折叠头部 */
    .tide-weaver summary {
      list-style: none;
      cursor: pointer;
      display: flex;
      align-items: center;
      padding: 4px 0;
      color: rgba(255, 255, 255, 0.85);
      position: relative;
    }
    .tide-weaver summary::-webkit-details-marker,
    .tide-weaver summary::marker { display: none; }

    /* 标题组 - 居中对齐 */
    .battle-title {
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: 2px;
      flex-shrink: 0;
      transition: all 0.3s ease;
      line-height: 1.3;
      padding: 0 16px;
    }
    .title-cn {
      font-size: 14px;
      font-weight: 500;
      letter-spacing: 0.1em;
      color: rgba(255, 255, 255, 0.85);
    }
    .title-en {
      font-size: 11px;
      font-weight: 400;
      color: rgba(255, 255, 255, 0.45);
      letter-spacing: 0.05em;
    }

    .tide-weaver summary:hover .battle-title {
      text-shadow: 0 0 8px rgba(77, 208, 225, 0.4);
    }

    /* 渐变分割线 - 拆分为左右两段以配合居中 */
    .separator-line {
      flex: 1;
      height: 1px;
      opacity: 0.4;
    }
    .separator-line.left-line {
      background: linear-gradient(270deg, #4dd0e1 0%, transparent 100%);
    }
    .separator-line.right-line {
      background: linear-gradient(90deg, #4dd0e1 0%, transparent 100%);
    }

    /* 箭头 */
    .arrow-icon {
      flex-shrink: 0;
      color: rgba(255, 255, 255, 0.4);
      transition: transform 0.3s ease;
      opacity: 0.7;
      margin-left: 12px;
    }
    .tide-weaver[open] summary .arrow-icon {
      transform: rotate(180deg);
    }

    /* 内容区 */
    .tide-content {
      max-height: 400px;
      overflow-y: auto;
      margin: 8px 0 8px 4px;
      padding: 4px 0 4px 14px;
      background: transparent;
    }
    .tide-weaver[open] .tide-content {
      animation: textFadeIn 0.4s ease forwards;
    }

    @keyframes textFadeIn {
      from { opacity: 0; transform: translateY(-4px); }
      to { opacity: 1; transform: translateY(0); }
    }

    /* 滚动条 */
    .tide-content::-webkit-scrollbar { width: 3px; }
    .tide-content::-webkit-scrollbar-track { background: transparent; }
    .tide-content::-webkit-scrollbar-thumb {
      background: rgba(255, 255, 255, 0.15);
      border-radius: 2px;
    }
    .tide-content::-webkit-scrollbar-thumb:hover { background: #4dd0e1; }

    /* 开关组 */
    .toggle-group {
      display: flex;
      align-items: center;
      gap: 12px;
      margin-bottom: 20px;
      opacity: 0.8;
    }
    .toggle-label {
      font-size: 11px;
      color: rgba(255, 255, 255, 0.4);
      letter-spacing: 0.05em;
    }
    .toggle-switch {
      width: 20px;
      height: 1px;
      background: rgba(255, 255, 255, 0.15);
      cursor: pointer;
      position: relative;
      transition: background 0.3s;
    }
    .toggle-switch::after {
      content: '';
      position: absolute;
      top: -2.5px;
      left: 0;
      width: 6px;
      height: 6px;
      background: rgba(255, 255, 255, 0.4);
      border-radius: 50%;
      transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
    }
    .toggle-switch.active { background: rgba(77, 208, 225, 0.3); }
    .toggle-switch.active::after {
      transform: translateX(14px);
      background: #4dd0e1;
      box-shadow: 0 0 6px rgba(77, 208, 225, 0.5);
    }

    /* 选项列表 */
    .option-list {
      display: flex;
      flex-direction: column;
      gap: 14px;
    }

    /* 选项按钮 */
    .option-btn {
      background: transparent;
      border: none;
      padding: 0;
      color: rgba(255, 255, 255, 0.85);
      font-family: "华文楷书", "STKaiti", "楷体", "KaiTi", "Noto Serif CJK SC", "Noto Serif JP", serif;
      font-weight: 400;
      font-size: 14px;
      line-height: 1.8;
      cursor: pointer;
      display: flex;
      align-items: flex-start;
      gap: 12px;
      transition: all 0.3s ease;
      text-align: left;
      white-space: pre-wrap;
    }
    .option-btn:hover {
      color: #80deea;
      transform: translateX(4px);
      text-shadow: 0 0 8px rgba(128, 222, 234, 0.3);
    }

    /* 极简序号 */
    .option-index {
      font-family: "Helvetica Neue", Helvetica, monospace;
      font-size: 11px;
      color: rgba(255, 255, 255, 0.3);
      padding-top: 5px;
      min-width: 16px;
      text-align: right;
      font-weight: 300;
    }

    /* 占位信息 */
    .empty-message, .error-message {
      font-family: "华文楷书", "STKaiti", "楷体", "KaiTi", "Noto Serif CJK SC", "Noto Serif JP", serif;
      color: rgba(255, 255, 255, 0.4);
      font-size: 13px;
      letter-spacing: 0.05em;
      padding: 8px 0;
    }
  </style>
</head>
<body>

<details class="tide-weaver" open>
  <summary>
    <span class="separator-line left-line"></span>
    <span class="battle-title">
      <span class="title-cn">潮汐抉择</span>
      <span class="title-en">Tide Choices</span>
    </span>
    <span class="separator-line right-line"></span>
    <svg class="arrow-icon" viewBox="0 0 16 16" width="12" height="12">
      <path d="M4 6l4 4 4-4" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" />
    </svg>
  </summary>

  <div class="tide-content">
    <div class="toggle-group">
      <span class="toggle-label">Direct Send</span>
      <div class="toggle-switch" id="directSendToggle"></div>
    </div>
    <div id="listRoot" class="option-list">
      <div class="empty-message">等待潮汐的涟漪...</div>
    </div>
  </div>
</details>

<script>
(function() {
  let directSend = true;
  let currentOptions = [];

  function getSTContext() {
    try {
      if (window.parent?.SillyTavern?.getContext) return window.parent.SillyTavern.getContext();
      if (window.SillyTavern?.getContext) return window.SillyTavern.getContext();
      if (window.top?.SillyTavern?.getContext) return window.top.SillyTavern.getContext();
      if (window.parent?.__SILLYTAVERN__?.getContext) return window.parent.__SILLYTAVERN__.getContext();
    } catch(e) { /* 跨域忽略 */ }
    return null;
  }

  function getLatestAssistantMessage() {
    const ctx = getSTContext();
    if (!ctx) return null;
    const chat = ctx.chat || ctx.messages || [];
    if (!chat.length) return null;
    for (let i = chat.length-1; i >= 0; i--) {
      const msg = chat[i];
      const role = msg.role || (msg.is_user === false ? 'assistant' : (msg.is_user ? 'user' : null));
      if (role === 'assistant' || msg.is_user === false || msg.type === 'assistant') {
        return msg.mes || msg.message || msg.content || '';
      }
    }
    return null;
  }

  function parseChoice(text) {
    if (!text) return [];
    const match = text.match(/<choice>([\s\S]*?)<\/choice>/i);
    if (!match) return [];
    const lines = match[1].split(/\r?\n/);
    const options = [];
    let idx = 1;
    for (let line of lines) {
      line = line.trim();
      if (!line) continue;
      const optMatch = line.match(/^\d+[\.\、\)]\s*(.*)/);
      let optText = optMatch ? optMatch[1].trim() : line;
      if (!optText) continue;
      options.push({ index: idx, text: optText });
      idx++;
    }
    return options;
  }

  function escapeHtml(str) {
    return str.replace(/[&<>]/g, function(m) {
      if (m === '&') return '&amp;';
      if (m === '<') return '&lt;';
      if (m === '>') return '&gt;';
      return m;
    });
  }

  function renderOptions() {
    const listRoot = document.getElementById('listRoot');
    if (!listRoot) return;
    listRoot.innerHTML = '';

    if (!currentOptions.length) {
      listRoot.innerHTML = '<div class="empty-message">等待潮汐的涟漪...</div>';
      return;
    }

    for (let opt of currentOptions) {
      const btn = document.createElement('button');
      btn.className = 'option-btn';
      const idxStr = opt.index.toString().padStart(2, '0');
      btn.innerHTML = `<span class="option-index">${idxStr}</span><span>${escapeHtml(opt.text)}</span>`;
      btn.onclick = () => handleSelect(opt.text);
      listRoot.appendChild(btn);
    }
  }

  function handleSelect(text) {
    try {
      const parentDoc = window.parent.document;
      const textarea = parentDoc.getElementById('send_textarea');
      if (!textarea) return;

      if (directSend) {
        textarea.value = text;
      } else {
        const cur = textarea.value;
        const sep = (cur && !cur.endsWith('\n')) ? ' ' : '';
        textarea.value = cur + sep + text;
      }

      textarea.dispatchEvent(new Event('input', { bubbles: true }));
      textarea.dispatchEvent(new Event('change', { bubbles: true }));

      if (directSend) {
        const ctx = getSTContext();
        if (ctx && typeof ctx.generate === 'function') ctx.generate();
        else {
          const sendBtn = parentDoc.getElementById('send_but');
          if (sendBtn) sendBtn.click();
        }
      }
    } catch(e) { console.warn(e); }
  }

  function saveDirectSend(val) {
    try {
      const ctx = getSTContext();
      if (ctx) {
        if (!ctx.extensionSettings) ctx.extensionSettings = {};
        if (!ctx.extensionSettings.TideOptions) ctx.extensionSettings.TideOptions = {};
        ctx.extensionSettings.TideOptions.directSend = val;
        if (ctx.saveSettingsDebounced) ctx.saveSettingsDebounced();
      } else {
        localStorage.setItem('tide_directSend', JSON.stringify(val));
      }
    } catch(e) {}
  }

  function loadDirectSend() {
    try {
      const ctx = getSTContext();
      if (ctx?.extensionSettings?.TideOptions?.directSend !== undefined) {
        return ctx.extensionSettings.TideOptions.directSend;
      }
    } catch(e) {}
    try {
      return JSON.parse(localStorage.getItem('tide_directSend') || 'true');
    } catch(e) {}
    return true;
  }

  function initToggle() {
    const toggle = document.getElementById('directSendToggle');
    if (!toggle) return;
    directSend = loadDirectSend();
    if (directSend) toggle.classList.add('active');

    toggle.onclick = (e) => {
      e.stopPropagation();
      directSend = !directSend;
      toggle.classList.toggle('active', directSend);
      saveDirectSend(directSend);
    };
  }

  function refresh() {
    const content = getLatestAssistantMessage();
    if (!content) {
      if (currentOptions.length) {
        currentOptions = [];
        renderOptions();
      }
      return;
    }
    const newOptions = parseChoice(content);
    if (JSON.stringify(newOptions) !== JSON.stringify(currentOptions)) {
      currentOptions = newOptions;
      renderOptions();
    }
  }

  function startPolling() {
    refresh();
    setInterval(refresh, 500);
    const ctx = getSTContext();
    if (ctx?.eventSource) {
      ctx.eventSource.on('messageRendered', refresh);
      ctx.eventSource.on('chatChanged', refresh);
    }
  }

  window.addEventListener('load', () => {
    initToggle();
    startPolling();
  });
})();
</script>
