<body>

<details class="tide-weaver" open>
  <summary>
    <span class="separator-line left-line"></span>
    <span class="battle-title">
      <span class="title-cn">潮汐抉择</span>
      <span class="title-en">Tide Choices</span>
    </span>
    <span class="separator-line right-line"></span>
    <svg class="arrow-icon" viewBox="0 0 16 16" width="12" height="12">
      <path d="M4 6l4 4 4-4" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" />
    </svg>
  </summary>

  <div class="tide-content">
    <div class="toggle-group">
      <span class="toggle-label">Direct Send</span>
      <div class="toggle-switch" id="directSendToggle"></div>
    </div>
    <div id="listRoot" class="option-list">
      <div class="empty-message">等待潮汐的涟漪...</div>
    </div>
  </div>
</details>

<script>
(function() {
  let directSend = true;
  let currentOptions = [];

  function getSTContext() {
    try {
      if (window.parent?.SillyTavern?.getContext) return window.parent.SillyTavern.getContext();
      if (window.SillyTavern?.getContext) return window.SillyTavern.getContext();
      if (window.top?.SillyTavern?.getContext) return window.top.SillyTavern.getContext();
      if (window.parent?.__SILLYTAVERN__?.getContext) return window.parent.__SILLYTAVERN__.getContext();
    } catch(e) { /* 跨域忽略 */ }
    return null;
  }

  function getLatestAssistantMessage() {
    const ctx = getSTContext();
    if (!ctx) return null;
    const chat = ctx.chat || ctx.messages || [];
    if (!chat.length) return null;
    for (let i = chat.length-1; i >= 0; i--) {
      const msg = chat[i];
      const role = msg.role || (msg.is_user === false ? 'assistant' : (msg.is_user ? 'user' : null));
      if (role === 'assistant' || msg.is_user === false || msg.type === 'assistant') {
        return msg.mes || msg.message || msg.content || '';
      }
    }
    return null;
  }

  function parseChoice(text) {
    if (!text) return [];
    const match = text.match(/<choice>([\s\S]*?)<\/choice>/i);
    if (!match) return [];
    const lines = match[1].split(/\r?\n/);
    const options = [];
    let idx = 1;
    for (let line of lines) {
      line = line.trim();
      if (!line) continue;
      const optMatch = line.match(/^\d+[\.\、\)]\s*(.*)/);
      let optText = optMatch ? optMatch[1].trim() : line;
      if (!optText) continue;
      options.push({ index: idx, text: optText });
      idx++;
    }
    return options;
  }

  function escapeHtml(str) {
    return str.replace(/[&<>]/g, function(m) {
      if (m === '&') return '&amp;';
      if (m === '<') return '&lt;';
      if (m === '>') return '&gt;';
      return m;
    });
  }

  function renderOptions() {
    const listRoot = document.getElementById('listRoot');
    if (!listRoot) return;
    listRoot.innerHTML = '';

    if (!currentOptions.length) {
      listRoot.innerHTML = '<div class="empty-message">等待潮汐的涟漪...</div>';
      return;
    }

    for (let opt of currentOptions) {
      const btn = document.createElement('button');
      btn.className = 'option-btn';
      const idxStr = opt.index.toString().padStart(2, '0');
      btn.innerHTML = `<span class="option-index">${idxStr}</span><span>${escapeHtml(opt.text)}</span>`;
      btn.onclick = () => handleSelect(opt.text);
      listRoot.appendChild(btn);
    }
  }

  function handleSelect(text) {
    try {
      const parentDoc = window.parent.document;
      const textarea = parentDoc.getElementById('send_textarea');
      if (!textarea) return;

      if (directSend) {
        textarea.value = text;
      } else {
        const cur = textarea.value;
        const sep = (cur && !cur.endsWith('\n')) ? ' ' : '';
        textarea.value = cur + sep + text;
      }

      textarea.dispatchEvent(new Event('input', { bubbles: true }));
      textarea.dispatchEvent(new Event('change', { bubbles: true }));

      if (directSend) {
        const ctx = getSTContext();
        if (ctx && typeof ctx.generate === 'function') ctx.generate();
        else {
          const sendBtn = parentDoc.getElementById('send_but');
          if (sendBtn) sendBtn.click();
        }
      }
    } catch(e) { console.warn(e); }
  }

  function saveDirectSend(val) {
    try {
      const ctx = getSTContext();
      if (ctx) {
        if (!ctx.extensionSettings) ctx.extensionSettings = {};
        if (!ctx.extensionSettings.TideOptions) ctx.extensionSettings.TideOptions = {};
        ctx.extensionSettings.TideOptions.directSend = val;
        if (ctx.saveSettingsDebounced) ctx.saveSettingsDebounced();
      } else {
        localStorage.setItem('tide_directSend', JSON.stringify(val));
      }
    } catch(e) {}
  }

  function loadDirectSend() {
    try {
      const ctx = getSTContext();
      if (ctx?.extensionSettings?.TideOptions?.directSend !== undefined) {
        return ctx.extensionSettings.TideOptions.directSend;
      }
    } catch(e) {}
    try {
      return JSON.parse(localStorage.getItem('tide_directSend') || 'true');
    } catch(e) {}
    return true;
  }

  function initToggle() {
    const toggle = document.getElementById('directSendToggle');
    if (!toggle) return;
    directSend = loadDirectSend();
    if (directSend) toggle.classList.add('active');

    toggle.onclick = (e) => {
      e.stopPropagation();
      directSend = !directSend;
      toggle.classList.toggle('active', directSend);
      saveDirectSend(directSend);
    };
  }

  function refresh() {
    const content = getLatestAssistantMessage();
    if (!content) {
      if (currentOptions.length) {
        currentOptions = [];
        renderOptions();
      }
      return;
    }
    const newOptions = parseChoice(content);
    if (JSON.stringify(newOptions) !== JSON.stringify(currentOptions)) {
      currentOptions = newOptions;
      renderOptions();
    }
  }

  function startPolling() {
    refresh();
    setInterval(refresh, 500);
    const ctx = getSTContext();
    if (ctx?.eventSource) {
      ctx.eventSource.on('messageRendered', refresh);
      ctx.eventSource.on('chatChanged', refresh);
    }
  }

  window.addEventListener('load', () => {
    initToggle();
    startPolling();
  });
})();
</script>
