    }
    .toggle-label {
      font-size: 11px;
      color: rgba(255, 255, 255, 0.4);
      letter-spacing: 0.05em;
    }
    .toggle-switch {
      width: 20px;
      height: 1px;
      background: rgba(255, 255, 255, 0.15);
      cursor: pointer;
      position: relative;
      transition: background 0.3s;
    }
    .toggle-switch::after {
      content: '';
      position: absolute;
      top: -2.5px;
      left: 0;
      width: 6px;
      height: 6px;
      background: rgba(255, 255, 255, 0.4);
      border-radius: 50%;
      transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
    }
    .toggle-switch.active { background: rgba(77, 208, 225, 0.3); }
    .toggle-switch.active::after {
      transform: translateX(14px);
      background: #4dd0e1;
      box-shadow: 0 0 6px rgba(77, 208, 225, 0.5);
    }

    /* 选项列表 */
    .option-list {
      display: flex;
      flex-direction: column;
      gap: 14px;
    }

    /* 选项按钮 */
    .option-btn {
      background: transparent;
      border: none;
      padding: 0;
      color: rgba(255, 255, 255, 0.85);
      font-family: "华文楷书", "STKaiti", "楷体", "KaiTi", "Noto Serif CJK SC", "Noto Serif JP", serif;
      font-weight: 400;
      font-size: 14px;
      line-height: 1.8;
      cursor: pointer;
      display: flex;
      align-items: flex-start;
      gap: 12px;
      transition: all 0.3s ease;
      text-align: left;
      white-space: pre-wrap;
    }
    .option-btn:hover {
      color: #80deea;
      transform: translateX(4px);
      text-shadow: 0 0 8px rgba(128, 222, 234, 0.3);
    }

    /* 极简序号 */
    .option-index {
      font-family: "Helvetica Neue", Helvetica, monospace;
      font-size: 11px;
      color: rgba(255, 255, 255, 0.3);
      padding-top: 5px;
      min-width: 16px;
      text-align: right;
      font-weight: 300;
    }

    /* 占位信息 */
    .empty-message, .error-message {
      font-family: "华文楷书", "STKaiti", "楷体", "KaiTi", "Noto Serif CJK SC", "Noto Serif JP", serif;
      color: rgba(255, 255, 255, 0.4);
