  // 检查注入占位符是否存在
  const hasBefore = content.includes('<|@D_before|>');
  const hasAfter = content.includes('<|@D_after|>');

  const settingsRegex = /<additional_settings>([\s\S]*?)<\/additional_settings>/g;
  const pivotTag = '<@D_Split>';
  const pivotIndex = content.indexOf(pivotTag);

  const beforeMatches =[];
  const afterMatches =[];

  // 遍历提取并处理标签内容
  let result = content.replace(settingsRegex, (match, innerText, offset) => {
    const isAfter = pivotIndex !== -1 && offset > pivotIndex;

    // 若目标位置缺少占位符，直接原样归位
    if ((!isAfter && !hasBefore) || (isAfter && !hasAfter)) {
      return innerText;
    }

    let contentToExtract = innerText;
    let contentToKeep = "";

    // 处理受保护的关键词：从提取内容中剔除，并留在原文
    const protectedKeywords = ["\n\n[Onset of the Dream]", "\n\nMingyue: ", "\n\nChaoxi: "];
    protectedKeywords.forEach(keyword => {
      if (contentToExtract.includes(keyword)) {
        contentToExtract = contentToExtract.replace(keyword, "");
        contentToKeep += keyword;
      }
    });

    // 提取有效内容并按锚点位置分组
    if (contentToExtract.trim()) {
      isAfter ? afterMatches.push(contentToExtract) : beforeMatches.push(contentToExtract);
    }

    return contentToKeep;
  });

  // 清理分割锚点
  result = result.replace(pivotTag, '');

  // 组合提取内容
  const beforeContent = beforeMatches.join('\n').trim();
  const afterContent = afterMatches.join('\n').trim();

  // 注入到对应占位符并清理残留标记
  result = result
    .replaceAll('<|@D_before|>', beforeContent ? '\n' + beforeContent : '')
    .replaceAll('<|@D_after|>', afterContent ? '\n' + afterContent : '');

  return result.trim();
